// translate() percentages for one step of one drawing id. [0, 0] if the
// id or step isn't in the table.
export function drawingAlign(id, stepIndex) {
  const [dx, dy] = DRAWING_ALIGN[id]?.[stepIndex] ?? [0, 0]
  return { dx: dx * 100, dy: dy * 100 }
}
